class Solution:
    def evenOddBit(self, n):
        bits = bin(n)[2:][::-1]
        even = sum(1 for i, c in enumerate(bits) if c == '1' and i % 2 == 0)
        odd = sum(1 for i, c in enumerate(bits) if c == '1' and i % 2 == 1)
        return [even, odd]

